export function getAllPosts(): BlogPost[] { return ALL_POSTS.filter(Boolean) }
export function getPost(slug: string): BlogPost | undefined { return ALL_POSTS.find(p => p && p.slug === slug) }
export function getPostsByCluster(cluster: string): BlogPost[] { return ALL_POSTS.filter(p => p && p.cluster === cluster) }
export function getRelatedPosts(post: BlogPost): BlogPost[] {
  return (post.relatedSlugs || []).map(s => ALL_POSTS.find(p => p && p.slug === s)).filter(Boolean) as BlogPost[]
}
